{
    "env": {
        "CLAUDE_CODE_NEW_INIT": "1"
    },
    "enabledPlugins": {
        "code-review@claude-plugins-official": true,
        "atlassian@claude-plugins-official": true,
        "typescript-lsp@claude-plugins-official": true,
        "pyright-lsp@claude-plugins-official": true,
        "superpowers@claude-plugins-official": true
    },
    "outputStyle": "Strict and Concise",
    "hooks": {
        "PreToolUse": [
            {
                "matcher": "Edit|Write",
                "hooks": [
                    {
                        "type": "command",
                        "command": "if [[ \"$CLAUDE_FILE_PATH\" == *\".env\"* && \"$CLAUDE_FILE_PATH\" != *\".env.example\"* && \"$CLAUDE_FILE_PATH\" != *\".env.test\"* && \"$CLAUDE_FILE_PATH\" != *\".env.test.example\"* ]]; then echo 'Blocked: editing .env files is not allowed'; exit 2; fi"
                    }
                ]
            }
        ],
        "Stop": [
            {
                "hooks": [
                    {
                        "type": "command",
                        "command": "case \"$TERM_PROGRAM\" in ghostty) B='com.mitchellh.ghostty';; iTerm.app) B='com.googlecode.iterm2';; WarpTerminal) B='dev.warp.Warp-Stable';; Apple_Terminal) B='com.apple.Terminal';; *) B='';; esac; terminal-notifier -title 'Claude Code' -message 'Claude finished' -sound 'Glass' ${B:+-activate \"$B\"} 2>/dev/null || true"
                    }
                ]
            }
        ],
        "Notification": [
            {
                "hooks": [
                    {
                        "type": "command",
                        "command": "case \"$TERM_PROGRAM\" in ghostty) B='com.mitchellh.ghostty';; iTerm.app) B='com.googlecode.iterm2';; WarpTerminal) B='dev.warp.Warp-Stable';; Apple_Terminal) B='com.apple.Terminal';; *) B='';; esac; MSG=$(jq -r '.message // \"Notification\"' 2>/dev/null || echo 'Notification'); terminal-notifier -title 'Claude Code' -message \"$MSG\" -sound 'Ping' ${B:+-activate \"$B\"} 2>/dev/null || true"
                    }
                ]
            }
        ]
    }
}
